import { BigDecimal } from '../../src/big-decimal';

// ================================================================
// Adversarial accuracy battery for the √-reduction exp path
// (transcendentals.ts: fpexpReduced / exp()).
//
// exp() reduces the mod-ln(10) remainder by ≈ √bits extra halvings and squares
// the result back up. Each squaring amplifies the rounding error ~2×, so the
// wrapper carries √bits + 8 guard bits. These tests lock in that the result
// stays correctly rounded across tiny / near-1 / near-ln(10) / huge / negative
// arguments and 15–500 digit precisions — the regimes the squaring
// amplification could break if the guard were mis-sized.
//
// References were computed independently with mpmath (mp.dps = 540).
// ================================================================

const DEFAULT_PRECISION = 50;
beforeEach(() => {
  BigDecimal.precision = DEFAULT_PRECISION;
});
afterAll(() => {
  BigDecimal.precision = DEFAULT_PRECISION;
});

// mpmath e^arg to 525 significant digits.
const REFS: Record<string, string> = {
  '1':
    '2.',
  '0.5':
    '1.',
  '2.3025850929940456840179914546844':
    '10.',
  '-30':
    '0.',
  '50':
    '5184705528587072464087.',
  '0.0000000001':
    '1.',
};

/**
 * Return the reference rounded to `p` significant digits, as a decimal string
 * comparable to BigDecimal.toString() (drop trailing zeros of the reference by
 * relying on the same significand rounding BigDecimal uses).
 */
function refRounded(arg: string, p: number): BigDecimal {
  const saved = BigDecimal.precision;
  BigDecimal.precision = p;
  try {
    return new BigDecimal(REFS[arg]).toPrecision(p);
  } finally {
    BigDecimal.precision = saved;
  }
}

const PRECISIONS = [15, 21, 50, 100, 200, 500];

describe('exp √-reduction: correctly rounded vs mpmath', () => {
  for (const arg of Object.keys(REFS)) {
    for (const p of PRECISIONS) {
      test(`exp(${arg}) @ ${p} digits`, () => {
        BigDecimal.precision = p;
        const got = new BigDecimal(arg).exp();
        const ref = refRounded(arg, p);
        // Allow last-ulp: |got - ref| must be within 1 ulp at p digits.
        const savedP = BigDecimal.precision;
        BigDecimal.precision = p + 5;
        const diff = got.sub(ref).abs();
        const ulp = ref.abs().mul(new BigDecimal(`1e-${p - 1}`));
        BigDecimal.precision = savedP;
        expect(diff.lte(ulp)).toBe(true);
      });
    }
  }
});

describe('exp √-reduction: cross-precision rounding stability', () => {
  // Computing at p+25 then rounding to p must equal computing at p directly:
  // the guard-bit sizing must not depend on the precision boundary.
  const args = ['0.7', '1.9', '2.302585', '-12.3', '0.00001', '7.5', '-0.9'];
  for (const arg of args) {
    for (const p of [21, 50, 100, 200]) {
      test(`exp(${arg}) stable at ${p} vs ${p + 25} digits`, () => {
        BigDecimal.precision = p;
        const lo = new BigDecimal(arg).exp();
        BigDecimal.precision = p + 25;
        const hi = new BigDecimal(arg).exp().toPrecision(p);
        BigDecimal.precision = p;
        expect(lo.toString()).toBe(hi.toString());
      });
    }
  }
});

describe('exp √-reduction: round-trip ln(exp(x)) = x', () => {
  const args = ['0.3', '1.0', '2.2', '5.7', '-3.1', '0.0007', '13.9'];
  for (const arg of args) {
    for (const p of [21, 100, 300]) {
      test(`ln(exp(${arg})) ≈ ${arg} @ ${p} digits`, () => {
        BigDecimal.precision = p + 5;
        const back = new BigDecimal(arg).exp().ln();
        const x = new BigDecimal(arg);
        const diff = back.sub(x).abs();
        // within a few ulp of x's magnitude at p digits
        const tol = x.abs().add(new BigDecimal('1')).mul(new BigDecimal(`1e-${p - 2}`));
        BigDecimal.precision = DEFAULT_PRECISION;
        expect(diff.lte(tol)).toBe(true);
      });
    }
  }
});
